#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N, Wmax; scanf("%d %d", &N, &Wmax);
        int *w = (int*)malloc(N*sizeof(int));
        long long *v = (long long*)malloc(N*sizeof(long long));
        for(int i=0;i<N;++i) scanf("%d %lld", &w[i], &v[i]);
        long long *dp = (long long*)calloc(Wmax+1, sizeof(long long));
        for(int i=0;i<N;++i){
            int wi = w[i]; long long vi = v[i];
            for(int cap=Wmax; cap>=wi; --cap){
                long long cand = dp[cap-wi] + vi;
                if(cand > dp[cap]) dp[cap] = cand;
            }
        }
        printf("%lld\n", dp[Wmax]);
        free(w); free(v); free(dp);
    }
    return 0;
}

