#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Wmax = int(next(it))
        weights = []
        values = []
        for __ in range(N):
            weights.append(int(next(it)))
            values.append(int(next(it)))
        dp = [0] * (Wmax + 1)
        for w, v in zip(weights, values):
            for cap in range(Wmax, w - 1, -1):
                cand = dp[cap - w] + v
                if cand > dp[cap]:
                    dp[cap] = cand
        out_lines.append(str(dp[Wmax]))
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

